mapper.select:
SELECT

FROM sys_user a

WHERE a.id = #{id}

SELECT

FROM sys_user a

WHERE a.login_name = #{loginName} AND a.del_flag = #{DEL_FLAG_NORMAL}

SELECT a.id, a.company_id AS "company.id", company.name AS "company.name", a.office_id AS "office.id", office.name AS "office.name", a.login_name AS "loginName", a.no, a.name, a.email, a.phone, a.mobile, a.user_type AS "userType", a.login_ip AS "loginIp", a.login_date AS "loginDate", a.remarks, a.login_flag AS "loginFlag", a.create_by AS "createBy.id", a.create_date, a.update_by AS "updateBy.id", a.update_date, a.del_flag, a.sso_login_flag AS "ssoLoginFlag", a.useable, a.sort AS "sortIndex", a.is_sys AS "isSys", a.sec_level AS "secLevel", a.login_exception_count AS "loginExceptionCount", a.password_expired_date AS "passwordExpiredDate", a.iim_status AS "status" FROM sys_user a LEFT JOIN sys_office office on office.id = a.office_id and office.del_flag = '0' LEFT JOIN sys_office company on company.id = a.company_id and company.del_flag = '0' WHERE a.del_flag = '0'
AND a.name LIKE #{nameLike}
AND 1 = 0

SELECT login_exception_count
FROM sys_user
WHERE login_name = #{loginName}

mapper.update:
update sys_user
set login_exception_count = 0
WHERE login_name = #{loginName}

