mapper.update:
update sys_user
set login_flag = '0'
WHERE login_name = #{loginName}

update sys_user
set login_exception_count = login_exception_count + 1
WHERE login_name = #{loginName}

update sys_user
set password = #{password}, password_expired_date = #{passwordExpiredDate}
WHERE login_name = #{loginName}

UPDATE sys_user SET
	login_name = #{loginName},
	name = #{name},
	user_type = #{userType},
	mobile = #{mobile}
WHERE no = #{no}

